import{_ as a,o as e,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const b=JSON.parse('{"title":"北大红楼","description":"","frontmatter":{},"headers":[],"relativePath":"history/peking-university-red.md","filePath":"history/peking-university-red.md","lastUpdated":null}'),o={name:"history/peking-university-red.md"};function n(i,t,d,h,s,g){return e(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="北大红楼" tabindex="-1">北大红楼 <a class="header-anchor" href="#北大红楼" aria-label="Permalink to &quot;北大红楼&quot;">​</a></h1><blockquote><p>&quot;新文化运动的摇篮，五四运动的发源地。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>北大红楼位于北京市东城区五四大街29号，是北京大学原校址。这座红楼建于1916年，是北京大学文科、校部及图书馆所在地。1919年五四运动在此爆发，标志着中国新民主主义革命的开端。2021年，北大红楼被列为全国重点文物保护单位。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">9:00-17:00（周一闭馆）</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">免费（需预约）</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">1-2小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">四季皆宜</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁8号线中国美术馆站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市东城区五四大街29号</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="始建" tabindex="-1">始建 <a class="header-anchor" href="#始建" aria-label="Permalink to &quot;始建&quot;">​</a></h3><p>北大红楼建于1916年，1918年竣工。建筑采用红砖砌成，故名&quot;红楼&quot;。这是当时北京最高的建筑之一，也是北京大学文科、校部及图书馆的所在地。</p><h3 id="新文化运动" tabindex="-1">新文化运动 <a class="header-anchor" href="#新文化运动" aria-label="Permalink to &quot;新文化运动&quot;">​</a></h3><p>1917年，蔡元培就任北京大学校长，实行&quot;思想自由，兼容并包&quot;的办学方针，聘请陈独秀、李大钊、胡适、鲁迅等新文化运动的领军人物到北大任教。</p><p>北大红楼成为新文化运动的中心，陈独秀主办的《新青年》杂志编辑部也设在这里。</p><h3 id="五四运动" tabindex="-1">五四运动 <a class="header-anchor" href="#五四运动" aria-label="Permalink to &quot;五四运动&quot;">​</a></h3><p>1919年5月4日，北京大学等13所高校3000余名学生在北大红楼集会，随后到天安门游行示威，火烧赵家楼，爆发了震惊中外的五四运动。</p><h3 id="马克思主义传播" tabindex="-1">马克思主义传播 <a class="header-anchor" href="#马克思主义传播" aria-label="Permalink to &quot;马克思主义传播&quot;">​</a></h3><p>1920年，李大钊在北大红楼建立了北京共产党早期组织，这是中国共产党成立前的重要准备。</p><h2 id="建筑特色" tabindex="-1">建筑特色 <a class="header-anchor" href="#建筑特色" aria-label="Permalink to &quot;建筑特色&quot;">​</a></h2><h3 id="外观" tabindex="-1">外观 <a class="header-anchor" href="#外观" aria-label="Permalink to &quot;外观&quot;">​</a></h3><p>北大红楼是一座四层砖木结构建筑，外观为红砖墙，红瓦顶，故名&quot;红楼&quot;。建筑风格为西洋古典式，庄重典雅。</p><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">数据</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>层数</strong></td><td style="text-align:left;">4层（地上）+ 1层（地下）</td></tr><tr><td style="text-align:left;"><strong>结构</strong></td><td style="text-align:left;">砖木结构</td></tr><tr><td style="text-align:left;"><strong>外墙</strong></td><td style="text-align:left;">红砖</td></tr><tr><td style="text-align:left;"><strong>风格</strong></td><td style="text-align:left;">西洋古典式</td></tr></tbody></table><h3 id="内部" tabindex="-1">内部 <a class="header-anchor" href="#内部" aria-label="Permalink to &quot;内部&quot;">​</a></h3><p>红楼内部保存了大量历史遗迹：</p><h4 id="李大钊办公室" tabindex="-1">李大钊办公室 <a class="header-anchor" href="#李大钊办公室" aria-label="Permalink to &quot;李大钊办公室&quot;">​</a></h4><p>李大钊曾任北大图书馆主任、教授，其办公室位于红楼一层。</p><h4 id="陈独秀办公室" tabindex="-1">陈独秀办公室 <a class="header-anchor" href="#陈独秀办公室" aria-label="Permalink to &quot;陈独秀办公室&quot;">​</a></h4><p>陈独秀曾任北大文科学长，其办公室也位于红楼。</p><h4 id="五四运动会议室" tabindex="-1">五四运动会议室 <a class="header-anchor" href="#五四运动会议室" aria-label="Permalink to &quot;五四运动会议室&quot;">​</a></h4><p>五四运动前，北大学生在此召开会议，筹划游行示威。</p><h4 id="毛泽东工作过的阅览室" tabindex="-1">毛泽东工作过的阅览室 <a class="header-anchor" href="#毛泽东工作过的阅览室" aria-label="Permalink to &quot;毛泽东工作过的阅览室&quot;">​</a></h4><p>1918年至1919年，毛泽东在北京大学图书馆工作，负责登记新到报刊和阅览者姓名。</p><h2 id="重要人物" tabindex="-1">重要人物 <a class="header-anchor" href="#重要人物" aria-label="Permalink to &quot;重要人物&quot;">​</a></h2><h3 id="蔡元培" tabindex="-1">蔡元培 <a class="header-anchor" href="#蔡元培" aria-label="Permalink to &quot;蔡元培&quot;">​</a></h3><p>蔡元培（1868-1940）是北京大学校长，提出&quot;思想自由，兼容并包&quot;的办学方针，使北大成为新文化运动的中心。</p><h3 id="陈独秀" tabindex="-1">陈独秀 <a class="header-anchor" href="#陈独秀" aria-label="Permalink to &quot;陈独秀&quot;">​</a></h3><p>陈独秀（1879-1942）是《新青年》杂志主编，新文化运动的倡导者，曾任北大文科学长。</p><h3 id="李大钊" tabindex="-1">李大钊 <a class="header-anchor" href="#李大钊" aria-label="Permalink to &quot;李大钊&quot;">​</a></h3><p>李大钊（1889-1927）是中国最早的马克思主义传播者，北大图书馆主任，中国共产党创始人之一。</p><h3 id="鲁迅" tabindex="-1">鲁迅 <a class="header-anchor" href="#鲁迅" aria-label="Permalink to &quot;鲁迅&quot;">​</a></h3><p>鲁迅（1881-1936）是新文化运动的旗手，曾任北大讲师，在红楼讲授中国小说史。</p><h3 id="胡适" tabindex="-1">胡适 <a class="header-anchor" href="#胡适" aria-label="Permalink to &quot;胡适&quot;">​</a></h3><p>胡适（1891-1962）是新文化运动的代表人物，提倡白话文，曾任北大教授。</p><h3 id="毛泽东" tabindex="-1">毛泽东 <a class="header-anchor" href="#毛泽东" aria-label="Permalink to &quot;毛泽东&quot;">​</a></h3><p>1918年，毛泽东第一次来北京，在北大红楼图书馆工作，深受新文化运动影响。</p><h2 id="新文化运动-1" tabindex="-1">新文化运动 <a class="header-anchor" href="#新文化运动-1" aria-label="Permalink to &quot;新文化运动&quot;">​</a></h2><p>新文化运动是1915年开始的一场思想启蒙运动，提倡民主和科学，反对专制和迷信；提倡新文学，反对旧文学；提倡白话文，反对文言文。</p><h3 id="主要内容" tabindex="-1">主要内容 <a class="header-anchor" href="#主要内容" aria-label="Permalink to &quot;主要内容&quot;">​</a></h3><ul><li><strong>提倡民主与科学</strong>：反对封建专制和迷信</li><li><strong>提倡新道德</strong>：反对旧礼教</li><li><strong>提倡新文学</strong>：反对旧文学</li><li><strong>提倡白话文</strong>：反对文言文</li></ul><h3 id="主要刊物" tabindex="-1">主要刊物 <a class="header-anchor" href="#主要刊物" aria-label="Permalink to &quot;主要刊物&quot;">​</a></h3><p>《新青年》是新文化运动的主要刊物，陈独秀主编，李大钊、胡适、鲁迅等为主要撰稿人。</p><h2 id="五四运动-1" tabindex="-1">五四运动 <a class="header-anchor" href="#五四运动-1" aria-label="Permalink to &quot;五四运动&quot;">​</a></h2><p>五四运动是1919年5月4日爆发的一场爱国运动，标志着中国新民主主义革命的开端。</p><h3 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to &quot;背景&quot;">​</a></h3><p>1919年，巴黎和会决定将德国在山东的权益转让给日本，引发中国人民强烈愤慨。</p><h3 id="经过" tabindex="-1">经过 <a class="header-anchor" href="#经过" aria-label="Permalink to &quot;经过&quot;">​</a></h3><p>1919年5月4日，北京大学等13所高校3000余名学生在北大红楼集会，发表宣言，随后到天安门游行示威，高呼&quot;外争主权，内除国贼&quot;&quot;废除二十一条&quot;等口号。</p><h3 id="结果" tabindex="-1">结果 <a class="header-anchor" href="#结果" aria-label="Permalink to &quot;结果&quot;">​</a></h3><p>五四运动迫使北洋政府拒绝在《巴黎和约》上签字，罢免了曹汝霖、章宗祥、陆宗舆的职务。</p><h3 id="意义" tabindex="-1">意义 <a class="header-anchor" href="#意义" aria-label="Permalink to &quot;意义&quot;">​</a></h3><p>五四运动标志着中国新民主主义革命的开端，促进了马克思主义在中国的传播。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>红楼参观（约1-2小时）</strong>：</p><p>入口 → 序厅 → 新文化运动展览 → 五四运动展览 → 李大钊办公室 → 陈独秀办公室 → 毛泽东阅览室 → 结束</p><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">站点</th></tr></thead><tbody><tr><td style="text-align:left;">地铁</td><td style="text-align:left;">8号线中国美术馆站A口</td></tr><tr><td style="text-align:left;">公交</td><td style="text-align:left;">103路、104路、111路等沙滩站</td></tr><tr><td style="text-align:left;">步行</td><td style="text-align:left;">从王府井步行约15分钟</td></tr></tbody></table><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>提前预约</strong>：纪念馆免费，但需提前预约</li><li><strong>讲解服务</strong>：建议请人工讲解，了解历史背景</li><li><strong>结合游览</strong>：可与故宫、中国美术馆一起游览</li><li><strong>教育意义</strong>：适合带孩子了解近代史</li><li><strong>周边景点</strong>：紧邻故宫、景山、北海</li></ol><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">中国美术馆</td><td style="text-align:center;">紧邻</td><td style="text-align:left;">国家级美术馆</td></tr><tr><td style="text-align:left;">故宫</td><td style="text-align:center;">步行15分钟</td><td style="text-align:left;">明清皇宫</td></tr><tr><td style="text-align:left;">景山公园</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">俯瞰故宫</td></tr><tr><td style="text-align:left;">北海公园</td><td style="text-align:center;">步行15分钟</td><td style="text-align:left;">皇家园林</td></tr><tr><td style="text-align:left;">王府井</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">商业街</td></tr></tbody></table><h2 id="文化价值" tabindex="-1">文化价值 <a class="header-anchor" href="#文化价值" aria-label="Permalink to &quot;文化价值&quot;">​</a></h2><p>北大红楼是中国近代史上的重要地标，是新文化运动和五四运动的发源地。</p><p>2021年6月，北大红楼被列为全国重点文物保护单位，并建成&quot;光辉伟业 红色序章——北大红楼与中国共产党早期北京革命活动主题展&quot;。</p><p>北大红楼见证了中国先进分子传播马克思主义、创建中国共产党的历史，是中国共产党的重要发祥地之一。</p><hr><p><strong>📍 地址</strong>：北京市东城区五四大街29号 <strong>📞 电话</strong>：010-52208901 <strong>🌐 官网</strong>：<a href="http://www.bdhonglou.cn" target="_blank" rel="noreferrer">www.bdhonglou.cn</a><strong>📱 预约</strong>：关注&quot;北大红楼&quot;微信公众号预约</p>',75)])])}const c=a(o,[["render",n]]);export{b as __pageData,c as default};
